# E2-Skeptic three-route assess for S51-T1-A-E2
def assess(record: dict) -> str:
    required = {'pii_in_trace', 'trace_id', 'spans', 'versions', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (not record["trace_id"] or record["pii_in_trace"])
    except Exception:
        return 'REDACT_AND_QUARANTINE_TRACE'
    return 'PASS' if ok else 'REDACT_AND_QUARANTINE_TRACE'

record = {"case_id": "CASO-MOQ-051-1A", **{"trace_id":"tr-moq-51","spans":{"prompt","retrieval","tool","answer"},"versions":{"prompt":"p3","model":"m2","index":"i4"},"pii_in_trace":False}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'pii_in_trace'}
print(assess(valid), assess(invalid), assess(incomplete))

